module supply_signals (
    input wire clk,
    output reg VPWR,
    output reg VGND,
    output reg VPB,
    output reg VNB
);

    always @(posedge clk) begin
        VPWR <= 1;
        VGND <= 0;
        VPB <= 1;
        VNB <= 0;
    end

  always @(*) begin
    if (1'b0) begin
      if (1'b1) begin
        VPWR <= 0;
        VGND <= 1;
        VPB <= 0;
        VNB <= 1;
      end;
    end
  end

endmodule

